    [Fact]
    public void Planner_GeneratesLogicalPlan_FromBoundStatement()
    {
        // Assemble
        var planner = new BogDb.Core.Planner.Planner();
        var boundStatement = new MockBoundStatement(StatementType.QUERY); // Dummy proxy until Phase 4 binder wires up natively

        // Act
        var plan = planner.GetBestPlan(boundStatement);

        // Assert: It should output a PROJECTION pointing to a SCAN.
        Assert.NotNull(plan);
        Assert.Equal(LogicalOperatorType.LOGICAL_PROJECTION, plan.LastOperator.OperatorType);
        
        var projection = (LogicalProjection)plan.LastOperator;
        Assert.True(projection.HasChild());
        
        var scan = projection.GetChild(0);
        Assert.Equal(LogicalOperatorType.LOGICAL_SCAN_NODE, scan.OperatorType);
    }

    [Fact]
    public void Planner_GeneratesFilterAndProjection_ForBoundRegularQuery()
    {
        var queryNode = new QueryNode(
            "n",
            "_0_n",
            new List<string> { "Person" },
            new List<PropertyExpression> { new("age", "n", LogicalTypeID.INT64) },
            new List<(string Key, Expression Value)>());
        var graph = new QueryGraph();
        graph.AddQueryNode(queryNode);

        var predicate = new BoundComparisonExpression(
            ExpressionType.EQUALS,
            new PropertyExpression("age", "n", LogicalTypeID.INT64),
            new LiteralExpression(40L, LogicalTypeID.INT64));
        var matchClause = new BoundMatchClause(graph, predicate);
        var returnClause = new BoundReturnClause(new List<BoundProjectionItem>
        {
            new(new PropertyExpression("age", "n", LogicalTypeID.INT64), "n.age")
        });

        var singleQuery = new NormalizedSingleQuery();
        singleQuery.AddReadingClause(matchClause);
        singleQuery.SetReturnClause(returnClause);

        var query = new BoundRegularQuery();
        query.AddSingleQuery(singleQuery);

        var planner = new BogDb.Core.Planner.Planner();
        var plan = planner.GetBestPlan(query);

        Assert.Equal(LogicalOperatorType.LOGICAL_PROJECTION, plan.LastOperator.OperatorType);
        var projection = (LogicalProjection)plan.LastOperator;
        Assert.Equal(LogicalOperatorType.LOGICAL_FILTER, projection.GetChild(0).OperatorType);
        var filter = (LogicalFilter)projection.GetChild(0);
        Assert.Equal(LogicalOperatorType.LOGICAL_SCAN_NODE, filter.GetChild(0).OperatorType);
    }

