    [Fact]
    public void Planner_UsesIndexScan_ForMultiPropertyInlineLookup()
    {
        using var db = BogDatabase.CreateInMemory();
        db.NodeTables["Person"] = new NodeTableData();
        db.CreateIndex("Person", "name");
        db.CreateIndex("Person", "age");

        var queryNode = new QueryNode(
            "p",
            "_0_p",
            new List<string> { "Person" },
            new List<PropertyExpression>
            {
                new("name", "p", LogicalTypeID.STRING),
                new("age", "p", LogicalTypeID.INT64)
            },
            new List<(string Key, Expression Value)>
            {
                ("name", new LiteralExpression("Alice", LogicalTypeID.STRING)),
                ("age", new LiteralExpression(30L, LogicalTypeID.INT64))
            });

        var graph = new QueryGraph();
        graph.AddQueryNode(queryNode);

        var singleQuery = new NormalizedSingleQuery();
        singleQuery.AddReadingClause(new BoundMatchClause(graph, null));
        singleQuery.SetReturnClause(new BoundReturnClause(new List<BoundProjectionItem>
        {
            new(new VariableExpression("p", LogicalTypeID.NODE), "p")
        }));

        var query = new BoundRegularQuery();
        query.AddSingleQuery(singleQuery);

        var planner = new BogDb.Core.Planner.Planner(db);
        var plan = planner.GetBestPlan(query);

        Assert.Equal(LogicalOperatorType.LOGICAL_PROJECTION, plan.LastOperator.OperatorType);
        var projection = Assert.IsType<LogicalProjection>(plan.LastOperator);
        Assert.Equal(LogicalOperatorType.LOGICAL_HASH_JOIN, projection.GetChild(0).OperatorType);
        var join = Assert.IsType<LogicalValueJoin>(projection.GetChild(0));
        var leftScan = Assert.IsType<LogicalIndexScanNode>(join.GetChild(0));
        var rightScan = Assert.IsType<LogicalIndexScanNode>(join.GetChild(1));
        Assert.Equal("Person", leftScan.TableName);
        Assert.Equal("Person", rightScan.TableName);
        Assert.Contains(leftScan.PropertyName, new[] { "name", "age" });
        Assert.Contains(rightScan.PropertyName, new[] { "name", "age" });
        Assert.NotEqual(leftScan.PropertyName, rightScan.PropertyName);
    }

