            new List<(string Key, Expression Value)>());

        var worksAt = new QueryRel(
            "r1",
            new List<string> { "WORKS_AT" },
            new List<QueryRelConnection> { new("WORKS_AT", "Person", "Company") },
            BogDb.Core.Parser.ArrowDirection.RIGHT,
            person,
            company,
            new List<PropertyExpression>(),
            new List<(string Key, Expression Value)>());
        var locatedIn = new QueryRel(
            "r2",
            new List<string> { "LOCATED_IN" },
            new List<QueryRelConnection> { new("LOCATED_IN", "Company", "Country") },
            BogDb.Core.Parser.ArrowDirection.RIGHT,
            company,
            country,
            new List<PropertyExpression>(),
            new List<(string Key, Expression Value)>());

        var longPart = new QueryPatternPart();
        longPart.AddNode(person);
        longPart.AddRel(worksAt);
        longPart.AddNode(company);
        longPart.AddRel(locatedIn);
        longPart.AddNode(country);

        var cityPart = new QueryPatternPart();
        cityPart.AddNode(city);

        var graph = new QueryGraph();
        graph.AddPatternPart(longPart);
        graph.AddPatternPart(cityPart);
        graph.AddQueryNode(person);
        graph.AddQueryNode(company);
        graph.AddQueryNode(country);
        graph.AddQueryNode(city);
        graph.AddQueryRel(worksAt);
        graph.AddQueryRel(locatedIn);

        var predicate = new BoundBooleanExpression(
            ExpressionType.AND,
            new BoundComparisonExpression(
                ExpressionType.EQUALS,
                new PropertyExpression("name", "c", LogicalTypeID.STRING),
                new LiteralExpression("Acme", LogicalTypeID.STRING)),
            new BoundComparisonExpression(
                ExpressionType.EQUALS,
                new PropertyExpression("code", "city", LogicalTypeID.STRING),
                new LiteralExpression("SEA", LogicalTypeID.STRING)));

        var singleQuery = new NormalizedSingleQuery();
        singleQuery.AddReadingClause(new BoundMatchClause(graph, predicate));
        singleQuery.SetReturnClause(new BoundReturnClause(new List<BoundProjectionItem>
        {
            new(new VariableExpression("c", LogicalTypeID.NODE), "c"),
            new(new VariableExpression("city", LogicalTypeID.NODE), "city")
        }));

        var query = new BoundRegularQuery();
        query.AddSingleQuery(singleQuery);

        var planner = new BogDb.Core.Planner.Planner(db);
        var plan = planner.GetBestPlan(query);

        var projection = Assert.IsType<LogicalProjection>(plan.LastOperator);
        var join = Assert.IsType<LogicalNestedLoopJoin>(projection.GetChild(0));
        var leftScan = Assert.IsType<LogicalIndexScanNode>(join.GetChild(0));
        Assert.Equal("City", leftScan.TableName);
        Assert.Equal("code", leftScan.PropertyName);
        Assert.Equal("SEA", leftScan.LookupKey);

        var outerTraverse = Assert.IsType<LogicalTraverseRel>(join.GetChild(1));
        var innerTraverse = Assert.IsType<LogicalTraverseRel>(outerTraverse.GetChild(0));
        var rightScan = Assert.IsType<LogicalIndexScanNode>(innerTraverse.GetChild(0));
        Assert.Equal("Company", rightScan.TableName);
        Assert.Equal("name", rightScan.PropertyName);
        Assert.Equal("Acme", rightScan.LookupKey);
    }

