        var topJoin = Assert.IsType<LogicalValueJoin>(projection.GetChild(0));
        Assert.IsType<LogicalIndexScanNode>(topJoin.GetChild(1));
        var outerTraverse = Assert.IsType<LogicalTraverseRel>(topJoin.GetChild(0));
        var innerTraverse = Assert.IsType<LogicalTraverseRel>(outerTraverse.GetChild(0));
        var join = Assert.IsType<LogicalValueJoin>(innerTraverse.GetChild(0));
        var leftScan = Assert.IsType<LogicalIndexScanNode>(join.GetChild(0));
        var rightScan = Assert.IsType<LogicalIndexScanNode>(join.GetChild(1));
