    [Fact]
    public void Planner_UsesIndexScan_ForInListPredicateOnIndexedProperty()
    {
        using var db = BogDatabase.CreateInMemory();
        db.NodeTables["Person"] = new NodeTableData();
        db.CreateIndex("Person", "name");

        var queryNode = new QueryNode(
            "p",
            "_0_p",
            new List<string> { "Person" },
            new List<PropertyExpression> { new("name", "p", LogicalTypeID.STRING) },
            new List<(string Key, Expression Value)>());

        var graph = new QueryGraph();
        graph.AddQueryNode(queryNode);

        // WHERE p.name IN ['Alice', 'Bob'] → list_contains(LIST_LITERAL('Alice','Bob'), p.name)
        var predicate = new BoundFunctionExpression(
            "list_contains",
            new Expression[]
            {
                new BoundFunctionExpression(
                    "LIST_LITERAL",
                    new Expression[]
                    {
                        new LiteralExpression("Alice", LogicalTypeID.STRING),
                        new LiteralExpression("Bob", LogicalTypeID.STRING)
                    },
                    LogicalTypeID.LIST),
                new PropertyExpression("name", "p", LogicalTypeID.STRING)
            },
            LogicalTypeID.BOOL);

        var singleQuery = new NormalizedSingleQuery();
        singleQuery.AddReadingClause(new BoundMatchClause(graph, predicate));
        singleQuery.SetReturnClause(new BoundReturnClause(new List<BoundProjectionItem>
        {
            new(new VariableExpression("p", LogicalTypeID.NODE), "p")
        }));

        var query = new BoundRegularQuery();
        query.AddSingleQuery(singleQuery);

        var planner = new BogDb.Core.Planner.Planner(db);
        var plan = planner.GetBestPlan(query);

        var projection = Assert.IsType<LogicalProjection>(plan.LastOperator);
        // Should produce a UNION ALL of two index scans (IN = OR, same property)
        var union = Assert.IsType<BogDb.Core.Planner.Operator.LogicalUnionAll>(projection.GetChild(0));
        var leftScan = Assert.IsType<LogicalIndexScanNode>(union.GetChild(0));
        var rightScan = Assert.IsType<LogicalIndexScanNode>(union.GetChild(1));
        Assert.Equal("Person", leftScan.TableName);
        Assert.Equal("Person", rightScan.TableName);
        Assert.Equal("name", leftScan.PropertyName);
        Assert.Equal("name", rightScan.PropertyName);
        Assert.Contains(leftScan.LookupKey, new object[] { "Alice", "Bob" });
        Assert.Contains(rightScan.LookupKey, new object[] { "Alice", "Bob" });
        Assert.NotEqual(leftScan.LookupKey, rightScan.LookupKey);
    }

    [Fact]
    public void Planner_UsesIndexPrefixScan_ForStartsWithOnIndexedProperty()
    {
        using var db = BogDatabase.CreateInMemory();
        using var conn = new BogConnection(db);
        conn.BeginWriteTransaction();
        conn.EnsureNodeTable("Person", new Dictionary<string, LogicalTypeID>
        {
            ["id"] = LogicalTypeID.STRING,
            ["name"] = LogicalTypeID.STRING
        });
        conn.Commit();
        db.CreateIndex("Person", "name");

        var graph = new QueryGraph();
        var node = new QueryNode(
            "p",
            "_0_p",
            new List<string> { "Person" },
            new List<PropertyExpression> { new("name", "p", LogicalTypeID.STRING) },
            new List<(string Key, Expression Value)>());
        graph.AddQueryNode(node);

        // starts_with(p.name, 'Al') — bound form of WHERE p.name STARTS WITH 'Al'
        var predicate = new BoundFunctionExpression(
            "starts_with",
            new Expression[]
            {
                new PropertyExpression("name", "p", LogicalTypeID.STRING),
                new LiteralExpression("Al", LogicalTypeID.STRING)
            },
            LogicalTypeID.BOOL);

        var singleQuery = new NormalizedSingleQuery();
        singleQuery.AddReadingClause(new BoundMatchClause(graph, predicate));
        singleQuery.SetReturnClause(new BoundReturnClause(new List<BoundProjectionItem>
        {
            new(new VariableExpression("p", LogicalTypeID.NODE), "p")
        }));

        var query = new BoundRegularQuery();
        query.AddSingleQuery(singleQuery);

        var planner = new BogDb.Core.Planner.Planner(db);
        var plan = planner.GetBestPlan(query);

        var projection = Assert.IsType<LogicalProjection>(plan.LastOperator);
        var indexScan = Assert.IsType<LogicalIndexScanNode>(projection.GetChild(0));
        Assert.Equal("Person", indexScan.TableName);
        Assert.Equal("name", indexScan.PropertyName);
        Assert.Equal("Al", indexScan.LookupKey);
        Assert.True(indexScan.IsPrefixScan, "Expected IsPrefixScan to be true for STARTS WITH");
    }

    [Fact]
    public void Planner_UsesIndexScan_ForWherePredicateWithInlineProperties()
    {
        // Pattern B: MATCH (p:Person {age: 30}) WHERE p.name = 'Alice' should use index on name
        using var db = BogDatabase.CreateInMemory();
        using var conn = new BogConnection(db);
        conn.BeginWriteTransaction();
        conn.EnsureNodeTable("Person", new Dictionary<string, LogicalTypeID>
        {
            ["id"] = LogicalTypeID.STRING,
            ["name"] = LogicalTypeID.STRING,
            ["age"] = LogicalTypeID.INT64
        });
        conn.Commit();
        db.CreateIndex("Person", "name");

        // Build the query: MATCH (p:Person {age: 30}) WHERE p.name = 'Alice' RETURN p
        var graph = new QueryGraph();
        var node = new QueryNode(
            "p",
            "_0_p",
            new List<string> { "Person" },
            new List<PropertyExpression>
            {
                new("name", "p", LogicalTypeID.STRING),
                new("age", "p", LogicalTypeID.INT64)
            },
            new List<(string Key, Expression Value)>
            {
                ("age", new LiteralExpression(30L, LogicalTypeID.INT64))
            });
        graph.AddQueryNode(node);

        var predicate = new BoundComparisonExpression(
            ExpressionType.EQUALS,
            new PropertyExpression("name", "p", LogicalTypeID.STRING),
            new LiteralExpression("Alice", LogicalTypeID.STRING));

        var singleQuery = new NormalizedSingleQuery();
        singleQuery.AddReadingClause(new BoundMatchClause(graph, predicate));
        singleQuery.SetReturnClause(new BoundReturnClause(new List<BoundProjectionItem>
        {
            new(new VariableExpression("p", LogicalTypeID.NODE), "p")
        }));

        var query = new BoundRegularQuery();
        query.AddSingleQuery(singleQuery);

        var planner = new BogDb.Core.Planner.Planner(db);
        var plan = planner.GetBestPlan(query);

        // The plan should contain an INDEX_SCAN for the name='Alice' predicate
        bool hasIndexScan = ContainsOperatorType(plan.LastOperator, LogicalOperatorType.LOGICAL_INDEX_SCAN_NODE);
        Assert.True(hasIndexScan, "Expected plan to contain INDEX_SCAN for WHERE predicate even when node has inline properties");
    }

    private static bool ContainsOperatorType(BogDb.Core.Planner.Operator.LogicalOperator op, LogicalOperatorType type)
    {
        if (op.OperatorType == type) return true;
        for (var i = 0; i < op.GetNumChildren(); i++)
        {
            if (ContainsOperatorType(op.GetChild(i), type))
                return true;
        }
        return false;
    }
